VALUES
  ('dietitian-moex-07694', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某老師剛開始進行臺灣東部原住民新陳代謝症候群的研究，預期探討生活飲食習慣和新陳代謝症候群， 因不了解臺灣東部原住民之飲食生活習慣，此時問卷應採用何種類型的題目？', '["結構型", "封閉型", "開放式", "表格式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07695', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是衛生教育學習領域的三個層面之一？', '["認知的層面", "情意的層面", "技能的層面", "環境的層面"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07696', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師在進行糖尿病營養諮詢時，能感受到接受諮詢者在節慶時，面對食物時無法控制食慾的感覺，稱 為：', '["同理心", "同情心", "認同心", "協同心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07697', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在PRECEDE-PROCEED模式中的第4個階段：教育及組織診斷，其主要目的在定義會影響預測和增強行 為的相關因素，使人們有良好的行為改變。則個人的知識、態度與信念是屬於其中的何種因素？', '["增強因素（reinforcing factors）", "使能因素（enabling factors）", "前傾因素（predisposing factors）", "控制因素（controling factor）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07698', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '若早期診斷、早期治療可以降低糖尿病患者的死亡率，在全面實施糖尿病防治工作後，可能產生的效應 是糖尿病的：', '["發生率降低", "盛行率降低", "侵襲率降低", "致死率降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07699', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養規劃有不同的層級。若規劃層級考慮到整個組織任務，且規劃2-3年的計畫，並重視此計畫應在 何處、何時、由誰做、如何做，以及利用何種資源來達成目標。此種規劃最可能是下列何者？', '["方案規劃（program planning）", "操作規劃（operational planning）", "策略規劃（strategic planning）", "執行規劃（active planning）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07700', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某縣市衛生局在一項社區營養規劃過程中，進行市場調查來決定社區民眾的需求，此種評量方式稱為：', '["結果評估（outcome evaluation）", "過程評估（process evaluation）", "形成性評估（formative evaluation）", "經濟評估（economic evaluation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07701', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者是近10年臺灣地區，國人十大死亡原因的第一名？', '["心臟疾病", "惡性腫瘤", "糖尿病", "腦血管疾病"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07702', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在規劃社區營養改善計畫時，根據國民營養調查結果，將民眾依不同年齡層、性別、居住地區及疾病型 態加以區分後，再依各族群特性分別訂定計畫內容。此種規劃方式稱為：', '["市場區隔", "分層規劃", "特殊化", "均質化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07703', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '完整的社區營養計畫過程，何者為第一步驟？', '["設計題材與教案", "尋求營養計畫推動所需的資源", "診斷社區營養問題", "尋找並瞭解前來聽宣導活動的民眾背景"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
